fn next_permutation<T: Ord>(arr: &mut [T]) -> bool {
    if arr.len() <= 1 {
        return false;
    }
    let i = match (0..arr.len()-1).rev().find(|&i| arr[i] < arr[i+1]) {
        Some(i) => i,
        None => return false,
    };
    let j = (i+1..arr.len()).rposition(|j| arr[j] > arr[i]).unwrap();
    arr.swap(i, j);
    arr[i+1..].reverse();
    true
}

fn distinct_permutations(items: &[u32]) -> Vec<Vec<u32>> {
    let mut data = items.to_vec();
    data.sort();
    let mut permutations = Vec::new();
    permutations.push(data.clone());
    while next_permutation(&mut data) {
        permutations.push(data.clone());
    }
    permutations
}

fn generate_candidates_17() -> Vec<i64> {
    let mut cand17 = Vec::new();
    for bit in 1..512 {
        let mut set = Vec::new();
        for d in 1..=9 {
            if bit >> (d-1) & 1 == 1 {
                set.push(d);
            }
        }
        let t: u32 = set.iter().sum();
        if t == 0 || t > 17 {
            continue;
        }
        let is_odd = t % 2 == 1;
        let mut odd_count = 0;
        for &d in &set {
            if d % 2 == 1 {
                odd_count += 1;
            }
        }
        if is_odd {
            if odd_count != 1 {
                continue;
            }
        } else {
            if odd_count != 0 {
                continue;
            }
        }

        if is_odd {
            let center = set.iter().find(|&&d| d % 2 == 1).cloned().unwrap();
            let mut multiset = Vec::new();
            for &d in &set {
                let count = if d == center { (d - 1) / 2 } else { d / 2 };
                for _ in 0..count {
                    multiset.push(d);
                }
            }
            let perms = distinct_permutations(&multiset);
            for perm in perms {
                let left_str: String = perm.iter().map(|d| d.to_string()).collect();
                let center_str = center.to_string();
                let mut right_vec = perm.clone();
                right_vec.reverse();
                let right_str: String = right_vec.iter().map(|d| d.to_string()).collect();
                let total_str = left_str + &center_str + &right_str;
                if let Ok(num) = total_str.parse() {
                    cand17.push(num);
                }
            }
        } else {
            let mut multiset = Vec::new();
            for &d in &set {
                let count = d / 2;
                for _ in 0..count {
                    multiset.push(d);
                }
            }
            let perms = distinct_permutations(&multiset);
            for perm in perms {
                let left_str: String = perm.iter().map(|d| d.to_string()).collect();
                let mut right_vec = perm.clone();
                right_vec.reverse();
                let right_str: String = right_vec.iter().map(|d| d.to_string()).collect();
                let total_str = left_str + &right_str;
                if let Ok(num) = total_str.parse() {
                    cand17.push(num);
                }
            }
        }
    }
    cand17
}

fn generate_min_cand_18() -> i64 {
    let set = vec![4, 6, 8];
    let mut multiset = Vec::new();
    for d in set {
        let count = d / 2;
        for _ in 0..count {
            multiset.push(d);
        }
    }
    multiset.sort();
    let left: String = multiset.iter().map(|d| d.to_string()).collect();
    let mut right = multiset.clone();
    right.reverse();
    let right: String = right.iter().map(|d| d.to_string()).collect();
    (left + &right).parse().unwrap()
}

pub fn solve(n: i64) -> i64 {
    let mut cand17 = generate_candidates_17();
    cand17.sort();
    cand17.dedup();
    for &cand in cand17.iter() {
        if cand > n {
            return cand;
        }
    }
    generate_min_cand_18()
}
