fn solve(n: i64) -> i64 {
    if n < 0 {
        return 1;
    }
    let n_str = n.to_string();
    let min_length = n_str.len();
    let max_total = 45;

    for total_length in min_length..=max_total {
        let mut min_candidate_value: Option<i64> = None;
        for bitmask in 1..(1 << 9) {
            let mut set = Vec::new();
            let mut sum_set = 0;
            for d in 1..=9 {
                if bitmask & (1 << (d-1)) != 0 {
                    set.push(d);
                    sum_set += d;
                }
            }
            if sum_set != total_length {
                continue;
            }

            let odd_count = set.iter().filter(|&d| d % 2 == 1).count();
            if total_length % 2 == 0 {
                if odd_count != 0 {
                    continue;
                }
            } else {
                if odd_count != 1 {
                    continue;
                }
            }

            let mut count = [0; 10];
            for &d in &set {
                count[d] = d;
            }
            let is_odd = total_length % 2 == 1;
            let half_len = (total_length + 1) / 2;

            if let Some(candidate_str) = generate_candidate_dfs(0, &mut String::new(), &mut count, &n_str, total_length, is_odd) {
                if candidate_str.parse::<i64>().map_or(false, |num| num > n) || 
                    (total_length > min_length) {
                    if let Ok(value) = candidate_str.parse::<i64>() {
                        if min_candidate_value.is_none() || value < min_candidate_value.unwrap() {
                            min_candidate_value = Some(value);
                        }
                    }
                }
            }
        }
        if let Some(value) = min_candidate_value {
            return value;
        }
    }

    panic!("No special number found for n={}", n);
}

fn generate_candidate_dfs(
    pos: usize,
    current: &mut String,
    count: &mut [usize; 10],
    n_str: &str,
    total_length: usize,
    is_odd: bool
) -> Option<String> {
    let h = (total_length + 1) / 2;
    if pos == h {
        let mirror_part = if is_odd {
            if current.len() <= 1 {
                "".to_string()
            } else {
                let s = &current[0..current.len()-1];
                s.chars().rev().collect::<String>()
            }
        } else {
            current.chars().rev().collect::<String>()
        };
        let candidate = current.clone() + &mirror_part;
        if total_length == n_str.len() {
            if candidate >= n_str {
                return Some(candidate);
            } else {
                return None;
            }
        } else {
            return Some(candidate);
        }
    }

    let at_center = (pos == h - 1) && is_odd;
    let required = if at_center { 1 } else { 2 };

    for d in 1..=9 {
        if count[d] < required {
            continue;
        }
        let ch = std::char::from_digit(d as u32, 10).unwrap();
        current.push(ch);
        count[d] -= required;

        let res = generate_candidate_dfs(pos + 1, current, count, n_str, total_length, is_odd);

        count[d] += required;
        current.pop();

        if res.is_some() {
            return res;
        }
    }
    None
}
