fn is_special(num: i64) -> bool {
    let s = num.to_string();
    if s != s.chars().rev().collect::<String>() {
        return false;
    }

    let mut counts = [0; 10];
    for c in s.chars() {
        let digit = c.to_digit(10).unwrap() as usize;
        if digit == 0 || digit >= 10 {
            return false;
        }
        counts[digit] += 1;
    }

    for k in 1..10 {
        if counts[k] != 0 && counts[k] != k {
            return false;
        }
    }

    true
}
